#include <stdio.h>
#include <stdlib.h>
#include <math.h>
int main(){
    int T;
    scanf("%d", &T);
    while (T--){
        int N;
        scanf("%d", &N);
        long long ans = 0;
        for (int i=0;i<N;i++){
            char vote;
            long long score;
            scanf(" %c %lld", &vote, &score);
            long long p = (vote=='P') ? 1LL : -1LL;
            long long other = score - p;
            long long cur = llabs(other);
            if (cur > ans) ans = cur;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

