const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
let T = parseInt(lines[i], 10);
i++;
let outputs = [];
while (T-- > 0) {
  let N = parseInt(lines[i], 10);
  i++;
  let ans = 0;
  for (let j = 0; j < N; j++) {
    const [vote, scoreStr] = lines[i].trim().split(/\s+/);
    i++;
    const p = (vote === 'P') ? 1 : -1;
    const other = Number(scoreStr) - p;
    const cur = Math.abs(other);
    if (cur > ans) ans = cur;
  }
  outputs.push(String(ans));
}
